var fixMarginCollapse = function(cssString) {
    var properties = cssString.split(';');
    for (var i = 0; i < properties.length; i++) {
        var property = properties[i].trim();
        if (property.startsWith('margin-top:')) {
            var marginTop = parseInt(property.split(':')[1]);
            if (marginTop > 0) {
                properties[i] = 'margin-top: ' + marginTop + ';';
            }
        } else if (property.startsWith('margin-bottom:')) {
            var marginBottom = parseInt(property.split(':')[1]);
            if (marginBottom > 0) {
                properties[i] = 'margin-bottom: ' + marginBottom + ';';
            }
        }
    }
    return properties.join(';');
};

solutions.javascript:
// define a function to fix margin collapse
var fixMarginCollapse = function(cssString) {
    var properties = cssString.split(';');
    for (var i = 0; i < properties.length; i++) {
        var property = properties[i].trim();
        if (property.startsWith('margin-top:')) {
            var marginTop = parseInt(property.split(':')[1]);
            var marginBottom = parseInt(property.split(':')[1]);
            properties[i] = 'margin-top: ' + marginTop + '; margin-bottom: ' + (marginTop + marginBottom) + ';';
        } else if (property.startsWith('margin-bottom:')) {
            var marginBottom = parseInt(property.split(':')[1]);
            var marginTop = parseInt(property.split(':')[1]);
            for (var j = 0; j < properties.length; j++) {
                if (properties[j].startsWith('margin-top:')) {
                    var marginTopValue = parseInt(properties[j].split(':')[1]);
                    properties[j] = 'margin-top: ' + marginTopValue + ';';
                }
            }
            properties[i] = 'margin-bottom: ' + (marginTop + marginBottom) + ';';
        }
    }
    return properties.join(';');
};
